    47→@PublicEvolving
    48→public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    49→    private static final long serialVersionUID = 1L;
    50→
    51→    private final String marketId;
    52→    private final ZoneId timezone;
    53→    private final LocalTime marketOpen;
    54→    private final LocalTime marketClose;
    55→
    56→    /**
    57→     * Creates a new {@code PricingSessionWindow} assigner.
    58→     *
    59→     * @param marketId The identifier for the market (e.g., "NYSE", "LSE")
    60→     * @param timezone The timezone for market hours interpretation
    61→     * @param marketOpen The market open time in the specified timezone
    62→     * @param marketClose The market close time in the specified timezone
    63→     */
    64→    public PricingSessionWindow(
    65→            String marketId, ZoneId timezone, LocalTime marketOpen, LocalTime marketClose) {
    66→        if (marketId == null || marketId.isEmpty()) {
    67→            throw new IllegalArgumentException("Market ID must not be null or empty");
    68→        }
    69→        if (timezone == null) {
    70→            throw new IllegalArgumentException("Timezone must not be null");
    71→        }
    72→        if (marketOpen == null) {
    73→            throw new IllegalArgumentException("Market open time must not be null");
    74→        }
    75→        if (marketClose == null) {
    76→            throw new IllegalArgumentException("Market close time must not be null");
    77→        }
    78→        if (!marketClose.isAfter(marketOpen)) {
    79→            throw new IllegalArgumentException("Market close time must be after market open time");
    80→        }
    81→
    82→        this.marketId = marketId;
    83→        this.timezone = timezone;
    84→        this.marketOpen = marketOpen;
    85→        this.marketClose = marketClose;
    86→    }
    87→
    88→    @Override
    89→    public Collection<TimeWindow> assignWindows(
    90→            Object element, long timestamp, WindowAssignerContext context) {
    91→        // Convert timestamp (millis) to ZonedDateTime
    92→        ZonedDateTime elementDateTime = ZonedDateTime.ofInstant(
    93→                java.time.Instant.ofEpochMilli(timestamp), timezone);
