    96→        long sessionStart = getSessionStart(elementDateTime);
    97→        long sessionEnd = getSessionEnd(elementDateTime);
    98→
    99→        // Check if this timestamp falls within today's trading session
   100→        if (timestamp >= sessionStart && timestamp < sessionEnd) {
   101→            return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
   102→        } else if (timestamp < sessionStart) {
   103→            // Element is before today's open, assign to today's session
   104→            return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
   105→        } else {
   106→            // Element is after today's close, assign to tomorrow's session
   107→            ZonedDateTime nextDay = elementDateTime.plusDays(1);
   108→            long nextSessionStart = getSessionStart(nextDay);
   109→            long nextSessionEnd = getSessionEnd(nextDay);
   110→            return Collections.singletonList(new TimeWindow(nextSessionStart, nextSessionEnd));
   111→        }
   112→    }
   113→
   114→    /**
   115→     * Calculates the session start timestamp (in milliseconds since epoch) for the given date in
   116→     * the market's timezone.
   117→     *
   118→     * @param dateTime The date to calculate the session start for
   119→     * @return The session start as milliseconds since epoch
   120→     */
   121→    private long getSessionStart(ZonedDateTime dateTime) {
   122→        ZonedDateTime sessionStart = dateTime
   123→                .withHour(marketOpen.getHour())
   124→                .withMinute(marketOpen.getMinute())
   125→                .withSecond(marketOpen.getSecond())
   126→                .withNano(marketOpen.getNano());
   127→        return sessionStart.toInstant().toEpochMilli();
   128→    }
   129→
   130→    /**
   131→     * Calculates the session end timestamp (in milliseconds since epoch) for the given date in the
   132→     * market's timezone.
   133→     *
   134→     * @param dateTime The date to calculate the session end for
   135→     * @return The session end as milliseconds since epoch
   136→     */
   137→    private long getSessionEnd(ZonedDateTime dateTime) {
   138→        ZonedDateTime sessionEnd = dateTime
   139→                .withHour(marketClose.getHour())
   140→                .withMinute(marketClose.getMinute())
   141→                .withSecond(marketClose.getSecond())
   142→                .withNano(marketClose.getNano());
   143→        return sessionEnd.toInstant().toEpochMilli();
   144→    }
