   153→        return "PricingSessionWindow(" + marketId + ", " + timezone + ", " + marketOpen + "-"
   154→                + marketClose + ")";
   155→    }
   156→
   157→    @Override
   158→    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
   159→        return new TimeWindow.Serializer();
   160→    }
   161→
   162→    @Override
   163→    public boolean isEventTime() {
   164→        return true;
   165→    }
   166→
   167→    @Override
   168→    public void mergeWindows(
   169→            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
   170→        TimeWindow.mergeWindows(windows, c);
   171→    }
