   175→     *
   176→     * @param marketId The identifier for the market (e.g., "NYSE", "LSE")
   177→     * @param timezone The timezone for market hours interpretation
   178→     * @param marketOpen The market open time
   179→     * @param marketClose The market close time
   180→     * @return A new PricingSessionWindow assigner
   181→     */
   182→    public static PricingSessionWindow forMarket(
   183→            String marketId, ZoneId timezone, LocalTime marketOpen, LocalTime marketClose) {
