import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.io.Serializable;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that windows elements into sessions based on market trading hours. This
 * assigner groups trading events by market session boundaries (e.g., NYSE 09:30-16:00 ET) rather
 * than fixed time intervals.
 *
 * <p>The window boundaries are determined by the market's open and close times in the specified
 * timezone. Each element is assigned to the trading session containing its timestamp.
 *
 * <p>Windows can overlap and be merged using the standard {@link TimeWindow} merging logic.
 *
 * @see org.apache.flink.streaming.api.windowing.assigners.EventTimeSessionWindows
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime marketOpen;
    private final LocalTime marketClose;

    /**
     * Creates a new {@code PricingSessionWindow} assigner.
     *
     * @param marketId The identifier for the market (e.g., "NYSE", "LSE")
     * @param timezone The timezone for market hours interpretation
     * @param marketOpen The market open time in the specified timezone
     * @param marketClose The market close time in the specified timezone
     */
    public PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime marketOpen, LocalTime marketClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID must not be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone must not be null");
        }
        if (marketOpen == null) {
            throw new IllegalArgumentException("Market open time must not be null");
        }
        if (marketClose == null) {
            throw new IllegalArgumentException("Market close time must not be null");
        }
        if (!marketClose.isAfter(marketOpen)) {
            throw new IllegalArgumentException("Market close time must be after market open time");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.marketOpen = marketOpen;
        this.marketClose = marketClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert timestamp (millis) to ZonedDateTime
        ZonedDateTime elementDateTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);

        // Get the session start and end times for this element's date
        long sessionStart = getSessionStart(elementDateTime);
        long sessionEnd = getSessionEnd(elementDateTime);

        // Check if this timestamp falls within today's trading session
        if (timestamp >= sessionStart && timestamp < sessionEnd) {
            return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
        } else if (timestamp < sessionStart) {
            // Element is before today's open, assign to today's session
            return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
        } else {
            // Element is after today's close, assign to tomorrow's session
            ZonedDateTime nextDay = elementDateTime.plusDays(1);
            long nextSessionStart = getSessionStart(nextDay);
            long nextSessionEnd = getSessionEnd(nextDay);
            return Collections.singletonList(new TimeWindow(nextSessionStart, nextSessionEnd));
        }
    }

    /**
     * Calculates the session start timestamp (in milliseconds since epoch) for the given date in
     * the market's timezone.
     *
     * @param dateTime The date to calculate the session start for
     * @return The session start as milliseconds since epoch
     */
    private long getSessionStart(ZonedDateTime dateTime) {
        ZonedDateTime sessionStart = dateTime
                .withHour(marketOpen.getHour())
                .withMinute(marketOpen.getMinute())
                .withSecond(marketOpen.getSecond())
                .withNano(marketOpen.getNano());
        return sessionStart.toInstant().toEpochMilli();
    }

    /**
     * Calculates the session end timestamp (in milliseconds since epoch) for the given date in the
     * market's timezone.
     *
     * @param dateTime The date to calculate the session end for
     * @return The session end as milliseconds since epoch
     */
    private long getSessionEnd(ZonedDateTime dateTime) {
        ZonedDateTime sessionEnd = dateTime
                .withHour(marketClose.getHour())
                .withMinute(marketClose.getMinute())
                .withSecond(marketClose.getSecond())
                .withNano(marketClose.getNano());
        return sessionEnd.toInstant().toEpochMilli();
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public String toString() {
        return "PricingSessionWindow(" + marketId + ", " + timezone + ", " + marketOpen + "-"
                + marketClose + ")";
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    /**
     * Creates a new {@code PricingSessionWindow} assigner for a specific market.
     *
     * @param marketId The identifier for the market (e.g., "NYSE", "LSE")
     * @param timezone The timezone for market hours interpretation
     * @param marketOpen The market open time
     * @param marketClose The market close time
     * @return A new PricingSessionWindow assigner
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime marketOpen, LocalTime marketClose) {
        return new PricingSessionWindow(marketId, timezone, marketOpen, marketClose);
    }
