package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} that fires at market close (window end) based on event time. This trigger is
 * specifically designed for pricing session windows in financial trading scenarios.
 *
 * <p>The trigger fires once the watermark passes the end of the window. It supports merging
 * windows by re-registering event time timers when windows are merged.
 *
 * @see org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // If the watermark is already past the window end, fire immediately
        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
            return TriggerResult.FIRE;
        } else {
            // Register a timer to fire at the window end
            ctx.registerEventTimeTimer(window.maxTimestamp());
            return TriggerResult.CONTINUE;
        }
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        // Fire when the timer for window end is triggered
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        return TriggerResult.CONTINUE;
    }

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        ctx.deleteEventTimeTimer(window.maxTimestamp());
    }

    @Override
    public boolean canMerge() {
        return true;
    }

    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) {
        // When windows merge, we need to re-register the timer for the new merged window end
        // Only register a timer if the watermark is not yet past the end of the merged window
        // This is in line with the logic in onElement() to avoid firing twice
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a pricing session trigger that fires once the watermark passes the end of the
     * window.
     *
     * <p>Once the trigger fires all elements are discarded. Elements that arrive late
     * immediately trigger window evaluation with just this one element.
     *
     * @return A new PricingSessionTrigger
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}

